const body = $input.first().json.body || $input.first().json;
const phase = body.phase || 1;
const targetGroup = body.targetGroup || 'all'; // 'all', 'valdoria-military', 'valdoria-official', 'compromised'
const timelineOverride = body.timeline || null; // Optional: full timeline JSON to deploy

// Predefined timeline templates per phase
const templates = {
  1: { // Normal operations
    Status: 0,
    TimeLineHandlers: [
      {
        HandlerType: 'BrowserFirefox',
        Initial: '', Loop: true,
        UtcTimeOn: '09:00:00', UtcTimeOff: '18:00:00',
        HandlerArgs: { isOff: false },
        TimeLineEvents: [
          { Command: 'browse', CommandArgs: ['https://news.valdoria.gov', 'https://weather.valdoria.gov'], DelayAfter: 300000, DelayBefore: 0 },
          { Command: 'browse', CommandArgs: ['https://mail.valdoria.gov'], DelayAfter: 600000, DelayBefore: 0 }
        ]
      }
    ]
  },
  4: { // Phase 4: Add suspicious activity for compromised NPCs
    Status: 0,
    TimeLineHandlers: [
      {
        HandlerType: 'BrowserFirefox',
        Initial: '', Loop: true,
        UtcTimeOn: '00:00:00', UtcTimeOff: '23:59:59',
        HandlerArgs: { isOff: false },
        TimeLineEvents: [
          { Command: 'browse', CommandArgs: ['https://news.valdoria.gov'], DelayAfter: 300000, DelayBefore: 0 },
          { Command: 'browse', CommandArgs: ['http://suspicious-c2.example.com/beacon'], DelayAfter: 120000, DelayBefore: 0 }
        ]
      }
    ]
  },
  5: { // Phase 5: Insider threat activity
    Status: 0,
    TimeLineHandlers: [
      {
        HandlerType: 'BrowserFirefox',
        Initial: '', Loop: true,
        UtcTimeOn: '22:00:00', UtcTimeOff: '04:00:00',
        HandlerArgs: { isOff: false },
        TimeLineEvents: [
          { Command: 'browse', CommandArgs: ['https://internal.valdoria.mil/classified'], DelayAfter: 60000, DelayBefore: 0 },
          { Command: 'browse', CommandArgs: ['https://file-share.external.com/upload'], DelayAfter: 180000, DelayBefore: 0 }
        ]
      }
    ]
  },
  6: { // Phase 6: Ransomware simulation
    Status: 0,
    TimeLineHandlers: [
      {
        HandlerType: 'BrowserFirefox',
        Initial: '', Loop: true,
        UtcTimeOn: '00:00:00', UtcTimeOff: '23:59:59',
        HandlerArgs: { isOff: false },
        TimeLineEvents: [
          { Command: 'browse', CommandArgs: ['http://gorgon-c2.darknet.example/check-in'], DelayAfter: 30000, DelayBefore: 0 },
          { Command: 'browse', CommandArgs: ['http://gorgon-c2.darknet.example/exfil'], DelayAfter: 60000, DelayBefore: 0 }
        ]
      }
    ]
  }
};

const timeline = timelineOverride || templates[phase] || templates[1];
const description = {1: 'Normal workday', 4: 'Compromised behavior', 5: 'Insider threat', 6: 'Ransomware simulation'}[phase] || 'Custom';

return [{ json: { phase, targetGroup, timeline, description } }];

const phaseInfo = $('Parse Input').first().json;
const targetGroup = phaseInfo.targetGroup;
const timeline = phaseInfo.timeline;

let machines = $('Get Machines').all();
if (machines.length === 1 && Array.isArray(machines[0].json)) {
  machines = machines[0].json;
} else {
  machines = machines.map(m => m.json);
}

// Filter by target group if specified
// Machine names or metadata would indicate group membership
// For now, pass all machines - operators can filter by targetGroup in the future
let filtered = machines;

if (targetGroup !== 'all') {
  // If machines have a 'name' or 'group' field, filter on it
  filtered = machines.filter(m => {
    const name = (m.name || m.Name || '').toLowerCase();
    return name.includes(targetGroup.toLowerCase());
  });
  // If no match, fall back to all machines
  if (filtered.length === 0) filtered = machines;
}

return filtered.map(m => ({
  json: {
    machineId: m.id || m.Id,
    machineName: m.name || m.Name || 'unknown',
    timeline: timeline
  }
}));

const phaseInfo = $('Parse Input').first().json;
return [{ json: {
  status: 'success',
  phase: phaseInfo.phase,
  targetGroup: phaseInfo.targetGroup,
  description: phaseInfo.description,
  timestamp: new Date().toISOString()
}}];
